import javax.swing.*;
import java.awt.*;

public class SafeSwingApp {
 public static void main(String[] args) {
 // Schedule UI creation on the EDT
 SwingUtilities.invokeLater(() -> {
 createAndShowGUI();
 });
 }

 private static void createAndShowGUI() {
 // Set look and feel before creating components
 try {
 UIManager.setLookAndFeel(
 UIManager.getSystemLookAndFeelClassName()
 );
 } catch (Exception e) {
 e.printStackTrace();
 }

 JFrame frame = new JFrame("Safe Swing App");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 frame.setLayout(new BorderLayout());

 JLabel label = new JLabel("Hello, Swing!", SwingConstants.CENTER);
 frame.add(label, BorderLayout.CENTER);

 frame.setSize(300, 200);
 frame.setLocationRelativeTo(null);
 frame.setVisible(true);
 }
}

import javax.swing.*;
import java.awt.*;
import java.awt.geom.Ellipse2D;

public class CustomCirclePanel extends JPanel {
 private Color fillColor = Color.BLUE;
 private int circleSize = 50;

 public CustomCirclePanel() {
 setPreferredSize(new Dimension(200, 200));
 setBackground(Color.WHITE);
 }

 @Override
 protected void paintComponent(Graphics g) {
 // Always call super first!
 super.paintComponent(g);

 // Cast to Graphics2D for advanced features
 Graphics2D g2d = (Graphics2D) g;
 g2d.setRenderingHint(
 RenderingHints.KEY_ANTIALIASING,
 RenderingHints.VALUE_ANTIALIAS_ON
 );

 // Calculate centered position
 int x = (getWidth() - circleSize) / 2;
 int y = (getHeight() - circleSize) / 2;

 // Draw the circle
 g2d.setColor(fillColor);
 g2d.fill(new Ellipse2D.Double(x, y, circleSize, circleSize));
 }

 public void setCircleColor(Color c) {
 fillColor = c;
 repaint(); // Request redraw - never call paintComponent directly!
 }

 public static void main(String[] args) {
 SwingUtilities.invokeLater(() -> {
 JFrame frame = new JFrame("Custom Painting");
 frame.add(new CustomCirclePanel());
 frame.pack();
 frame.setVisible(true);
 });
 }
}

import javax.swing.*;
import java.awt.*;
import java.util.Random;

public class SwingWorkerDemo extends JFrame {
 private JLabel statusLabel;
 private JButton startButton;
 private JProgressBar progressBar;

 public SwingWorkerDemo() {
 setLayout(new BorderLayout(5, 5));

 statusLabel = new JLabel("Ready", SwingConstants.CENTER);
 progressBar = new JProgressBar(0, 100);
 startButton = new JButton("Start Long Task");

 add(statusLabel, BorderLayout.NORTH);
 add(progressBar, BorderLayout.CENTER);
 add(startButton, BorderLayout.SOUTH);

 startButton.addActionListener(e -> startLongTask());

 setSize(300, 150);
 setDefaultCloseOperation(EXIT_ON_CLOSE);
 }

 private void startLongTask() {
 startButton.setEnabled(false);

 // Create SwingWorker
 SwingWorker<Integer, Integer> worker = new SwingWorker<>() {
 @Override
 protected Integer doInBackground() throws Exception {
 // Runs on background thread - heavy work here!
 int total = 0;
 for (int i = 0; i <= 100; i++) {
 Thread.sleep(30); // Simulate work
 publish(i); // Publish progress to EDT
 }
 return total;
 }

 @Override
 protected void process(Integer... chunks) {
 // Runs on EDT - update UI here
 int latest = chunks[chunks.length - 1];
 progressBar.setValue(latest);
 statusLabel.setText("Progress: " + latest + "%");
 }

 @Override
 protected void done() {
 // Runs on EDT - final updates
 startButton.setEnabled(true);
 statusLabel.setText("Task Complete!");
 }
 };

 worker.execute();
 }

 public static void main(String[] args) {
 SwingUtilities.invokeLater(() -> 
 new SwingWorkerDemo().setVisible(true)
 );
 }
}
